/*
 * psmgr_sock.c - Protocol Session Manager: session establishment path
 *
 * Implements socket creation, bind, connect, and the setsockopt-driven
 * handshake. For INITIATOR/RESPONDER sessions, the handshake is distributed:
 *
 *   INITIATOR side:  calls PSMGR_OPT_SET_ROLE, then PSMGR_OPT_NEGO_1 to
 *                contribute enc_class and xfrm_type (transport parameters).
 *                Then calls connect() to the RESPONDER peer's session_id.
 *                connect() triggers the kernel to assemble the full context
 *                from both contributions and mark both sessions ESTABLISHED.
 *
 *   RESPONDER side: calls PSMGR_OPT_SET_ROLE, then PSMGR_OPT_NEGO_2 to
 *                contribute enc_mode and proc_param (processing parameters).
 *                Then calls bind() to register its session_id as addressable.
 *                The INITIATOR's connect() completes the handshake.
 *
 * MANAGED sessions bypass the distributed handshake entirely: one socket
 * supplies all parameters via PSMGR_OPT_LOCAL_CTX with combined validation.
 *
 * FORWARD sessions pair two sockets via connect() for bidirectional initiator.
 */

