/* -------------------------------------------------------------------------
 * Session ID allocator
 * ---------------------------------------------------------------------- */

static atomic_t psmgr_id_counter = ATOMIC_INIT(1);

u32 psmgr_session_alloc_id(void)
{
	return (u32)atomic_inc_return(&psmgr_id_counter);
}

/* -------------------------------------------------------------------------
 * Session table operations
 * ---------------------------------------------------------------------- */

struct psmgr_session *psmgr_session_lookup(struct psmgr_net *pn, u32 id)
{
	struct list_head *bucket = psmgr_session_bucket(pn, id);
	struct psmgr_session *sess;

	list_for_each_entry(sess, bucket, node) {
		if (sess->session_id == id)
			return sess;
	}
	return NULL;
}

void psmgr_session_put(struct psmgr_session *sess)
{
	if (refcount_dec_and_test(&sess->refcnt)) {
		kfree(sess->desc);
		kfree(sess);
	}
}

