static int psmgr_process_ctrl(struct psmgr_session *sess,
			      const u8 *payload, u16 payload_len)
{
	struct psmgr_ctrl_payload cp;

	if (payload_len < sizeof(cp))
		return -EINVAL;

	memcpy(&cp, payload, sizeof(cp));

	switch (cp.subtype) {
	case PSMGR_CTRL_RESET: {
		if (sess->desc->token != 0) {
			pr_debug("psmgr: session %u CTRL RESET rejected: token set\n",
					 sess->session_id);
			return -EPROTO;
		}
		memset(sess->desc, 0, sizeof(*sess->desc));
		sess->next_seq = 0;
		pr_debug("psmgr: session %u CTRL RESET\n", sess->session_id);
		break;
	}
	case PSMGR_CTRL_PAUSE:
		sess->paused = 1;
		pr_debug("psmgr: session %u CTRL PAUSE\n", sess->session_id);
		break;
	case PSMGR_CTRL_RESUME:
		sess->paused = 0;
		pr_debug("psmgr: session %u CTRL RESUME\n", sess->session_id);
		break;
	case PSMGR_CTRL_STATUS_REQ:
		pr_debug("psmgr: session %u CTRL STATUS_REQ write_count=%u\n",
				 sess->session_id, sess->desc->write_count);
		break;
	default:
		pr_debug("psmgr: session %u CTRL unknown subtype=0x%02x\n",
				 sess->session_id, cp.subtype);
		return -EPROTO;
	}

	sess->stats.ctrl_msgs_rx++;
	sess->stats.last_rx = ktime_get();
	return 0;
}

static int psmgr_process_commit_req(struct psmgr_session *sess,
				    const u8 *payload, u16 payload_len)
{
	struct psmgr_desc *pb = sess->desc;
	struct psmgr_commit_req_payload cpl;

	if (pb->write_count == PSMGR_BUF_COMMITTED ||
		pb->write_count < PSMGR_BUF_WRITE_THRESH ||
		pb->token == 0) {
		pr_debug("psmgr: session %u COMMIT_REQ rejected: "
				 "write_count=0x%08x token=0x%08x\n",
				 sess->session_id, pb->write_count, pb->token);
		return -EPROTO;
	}

	if (pb->handler != NULL) {
		/* Handler already installed; skip table resolution. */
		pr_debug("psmgr: session %u COMMIT_REQ: handler pre-installed\n",
				 sess->session_id);
	} else {
		if (payload_len < sizeof(cpl))
			return -EINVAL;
		memcpy(&cpl, payload, sizeof(cpl));
		if (cpl.handler_idx >= PSMGR_HANDLER_MAX) {
			pr_debug("psmgr: session %u COMMIT_REQ: handler_idx=%u out of range\n",
					 sess->session_id, cpl.handler_idx);
			return -ERANGE;
		}
		pb->handler = psmgr_handlers[cpl.handler_idx];
		pr_debug("psmgr: session %u COMMIT_REQ: handler[%u] installed\n",
				 sess->session_id, cpl.handler_idx);
	}

	pb->write_count = PSMGR_BUF_COMMITTED;
	pr_debug("psmgr: session %u COMMIT_REQ: finalized\n", sess->session_id);

	sess->stats.commit_reqs_rx++;
	sess->stats.last_rx = ktime_get();
	return 0;
}

/* -------------------------------------------------------------------------
 * poll
 *
 * Reports readability when desc state has changed since the last
 * recvmsg (i.e. any DATA write has occurred or the buffer is complete).
 * Writability is always reported: sendmsg does not block.
 * ---------------------------------------------------------------------- */

__poll_t psmgr_poll(struct file *file, struct socket *sock,
		    struct poll_table_struct *wait)
{
	struct sock *sk = sock->sk;
	struct psmgr_sock *psk = psmgr_sk(sk);
	struct psmgr_session *sess = psk->session;
	__poll_t mask = EPOLLOUT | EPOLLWRNORM;

	sock_poll_wait(file, sock, wait);

	if (!sess || !sess->validated)
		return mask;

	spin_lock_bh(&sess->lock);
	if (sess->desc->write_count > 0 || sess->desc->token != 0)
		mask |= EPOLLIN | EPOLLRDNORM;
	spin_unlock_bh(&sess->lock);

	return mask;
}

