265	
266		if (out_offset < PSMGR_BUF_DATA_SZ && write_limit > PSMGR_BUF_DATA_SZ)
267			write_limit = PSMGR_BUF_DATA_SZ;
268	
269		/* RESPONDER: apply window_sz limit if set */
270		if (sess->role == PSMGR_ROLE_RESPONDER && sess->ctx.window_sz > 0) {
271			u32 responder_limit = (u32)out_offset + (u32)sess->ctx.window_sz;
272			if (responder_limit < write_limit)
273				write_limit = responder_limit;
274		}
275	
276		copy_len = min_t(u16, payload_len,
277						 (u16)(write_limit -
278							   min_t(u32, out_offset, write_limit)));
279	
280		if (copy_len == 0)
281			return 0;
282	
283		memcpy((u8 *)pb + out_offset, payload, copy_len);
284	
285		psmgr_write_count_update(sess, out_offset);
286	
287		sess->stats.data_msgs_rx++;
288		sess->stats.data_bytes_rx += copy_len;
289		sess->stats.last_rx = ktime_get();
290	
291		if (sess->sk)
292			sess->sk->sk_data_ready(sess->sk);
293	
294		return (int)copy_len;
295	}
