301	static int psmgr_process_ctrl(struct psmgr_session *sess,
302				      const u8 *payload, u16 payload_len)
303	{
304		struct psmgr_ctrl_payload cp;
305	
306		if (payload_len < sizeof(cp))
307			return -EINVAL;
308	
309		memcpy(&cp, payload, sizeof(cp));
310	
311		switch (cp.subtype) {
312		case PSMGR_CTRL_RESET: {
313			if (sess->desc->token != 0) {
