331		case PSMGR_CTRL_STATUS_REQ:
332			pr_debug("psmgr: session %u CTRL STATUS_REQ write_count=%u\n",
333					 sess->session_id, sess->desc->write_count);
334			break;
335		default:
336			pr_debug("psmgr: session %u CTRL unknown subtype=0x%02x\n",
337					 sess->session_id, cp.subtype);
338			return -EPROTO;
339		}
340	
341		sess->stats.ctrl_msgs_rx++;
342		sess->stats.last_rx = ktime_get();
343		return 0;
344	}
