101	/* -------------------------------------------------------------------------
102	 * out_offset computation
103	 * ---------------------------------------------------------------------- */
104	
105	static u32 compute_out_offset(u8 xfrm_type, u8 enc_mode, u32 proc_param)
106	{
107		switch (xfrm_type) {
108		case PSMGR_XFRM_SCATTER:
109			switch (enc_mode) {
110			case PSMGR_MODE_LINEAR:     return proc_param * 2;
111			case PSMGR_MODE_INTERLEAVE: return proc_param * 4;
112			case PSMGR_MODE_FOLD:       return proc_param * 8;
113			}
114			break;
115		case PSMGR_XFRM_WINDOW:
116			switch (enc_mode) {
117			case PSMGR_MODE_LINEAR:     return proc_param;
118			case PSMGR_MODE_INTERLEAVE: return proc_param * 2;
119			case PSMGR_MODE_FOLD:       return proc_param * 4;
120			}
121			break;
122		case PSMGR_XFRM_COMMIT:
123			switch (enc_mode) {
124			case PSMGR_MODE_LINEAR:     return proc_param * 4;
125			case PSMGR_MODE_INTERLEAVE: return proc_param * 8;
126			case PSMGR_MODE_FOLD:       return proc_param * 16;
127			}
128			break;
129		case PSMGR_XFRM_REFLECT:
130			switch (enc_mode) {
131			case PSMGR_MODE_LINEAR:     return proc_param;
132			case PSMGR_MODE_INTERLEAVE: return (proc_param ^ (proc_param >> 1)) * 2;
133			case PSMGR_MODE_FOLD:       return proc_param * 4;
134			}
135			break;
136		}
137		return UINT_MAX;
138	}
