140	/* -------------------------------------------------------------------------
141	 * token computation
142	 * ---------------------------------------------------------------------- */
143	
144	static void psmgr_compute_token(struct psmgr_session *sess)
145	{
146		sess->desc->token =
147			(sess->session_id ^ sess->nonce ^ 0xA5C3E1F0) | 0x80000000;
148		pr_debug("psmgr: session %u token set: 0x%08x\n",
149				 sess->session_id, sess->desc->token);
150	}
