152	/* -------------------------------------------------------------------------
153	 * Completion counter update
154	 *
155	 * Called after every DATA write. 
156	 *
157	 * When write_count reaches PSMGR_BUF_WRITE_THRESH and token has not
158	 * yet been set, the kernel computes and installs token.
159	 * ---------------------------------------------------------------------- */
160	
161	static void psmgr_write_count_update(struct psmgr_session *sess, u32 out_offset)
162	{
163		struct psmgr_desc *pb = sess->desc;
164	
165		if (out_offset < PSMGR_BUF_DATA_SZ) {
166			/* Increment the completion counter, capped at the threshold. */
167			if (pb->write_count < PSMGR_BUF_WRITE_THRESH)
168				pb->write_count++;
169		}
170	
171		if (pb->write_count >= PSMGR_BUF_WRITE_THRESH && pb->token == 0) {
172			psmgr_compute_token(sess);
173			pr_debug("psmgr: session %u buffer complete, token set\n",
174					 sess->session_id);
175		}
176	}
