193			return -EBUSY;
194		}
195	
196		if (pb->write_count == PSMGR_BUF_COMMITTED) {
197			pr_debug("psmgr: session %u DATA rejected: already finalized\n",
198					 sess->session_id);
199			return -EPROTO;
200		}
201	
202		out_offset = compute_out_offset(sess->ctx.xfrm_type,
203						sess->ctx.enc_mode,
204						sess->ctx.proc_param);
