206		if (out_offset == UINT_MAX) {
207			pr_debug("psmgr: session %u unknown xfrm/enc_mode\n",
208					 sess->session_id);
209			return -EPROTO;
210		}
211	
212		/*
213		 * Per-transform semantic validation.
214		 *
215		 * SCATTER: offset must be stride-aligned and within the data region.
216		 * COMMIT:  offset must be 4-byte aligned and within the data region.
217		 * REFLECT: reflected offset must lie within the data region.
218		 * WINDOW:  no secondary check; handshake guarantee is the sole validator.
219		 */
220		switch (sess->ctx.xfrm_type) {
221		case PSMGR_XFRM_SCATTER: {
222			u32 stride = (sess->ctx.enc_mode == PSMGR_MODE_LINEAR)    ? 2 :
223						 (sess->ctx.enc_mode == PSMGR_MODE_INTERLEAVE) ? 4 : 8;
224			if (out_offset >= PSMGR_BUF_DATA_SZ ||
225				(out_offset % stride) != 0) {
226				pr_debug("psmgr: session %u SCATTER offset invalid: "
227						 "out_offset=%u stride=%u\n",
228						 sess->session_id, out_offset, stride);
229				return -EPROTO;
230			}
231			break;
232		}
233		case PSMGR_XFRM_COMMIT:
234			if (out_offset >= PSMGR_BUF_DATA_SZ || (out_offset & 0x3) != 0) {
235				pr_debug("psmgr: session %u COMMIT offset invalid: "
236						 "out_offset=%u\n", sess->session_id, out_offset);
237				return -EPROTO;
238			}
239			break;
240		case PSMGR_XFRM_REFLECT:
241			if (out_offset >= PSMGR_BUF_DATA_SZ) {
242				pr_debug("psmgr: session %u REFLECT offset out of region: "
243						 "out_offset=%u\n", sess->session_id, out_offset);
244				return -EPROTO;
245			}
246			break;
247		case PSMGR_XFRM_WINDOW:
248			break;
249		}
250	
251		/*
252		 * Global upper bound: reject writes beyond the end of desc.
253		 */
254		if (sess->role != PSMGR_ROLE_MANAGED &&
255			out_offset >= PSMGR_BUF_TOTAL_SZ) {
256			pr_debug("psmgr: session %u DATA rejected: out_offset=%u >= BUF_TOTAL_SZ\n",
257					 sess->session_id, out_offset);
258			return -ERANGE;
259		}
260	
261		if (pb->token != 0)
262			write_limit = PSMGR_BUF_TOTAL_SZ;
263		else
264			write_limit = PSMGR_BUF_DATA_SZ + (u32)sizeof(u32);
265	
266		if (out_offset < PSMGR_BUF_DATA_SZ && write_limit > PSMGR_BUF_DATA_SZ)
267			write_limit = PSMGR_BUF_DATA_SZ;
268	
269		/* RESPONDER: apply window_sz limit if set */
270		if (sess->role == PSMGR_ROLE_RESPONDER && sess->ctx.window_sz > 0) {
271			u32 responder_limit = (u32)out_offset + (u32)sess->ctx.window_sz;
272			if (responder_limit < write_limit)
273				write_limit = responder_limit;
274		}
275	
276		copy_len = min_t(u16, payload_len,
277						 (u16)(write_limit -
278							   min_t(u32, out_offset, write_limit)));
279	
280		if (copy_len == 0)
281			return 0;
282	
283		memcpy((u8 *)pb + out_offset, payload, copy_len);
284	
285		psmgr_write_count_update(sess, out_offset);
286	
287		sess->stats.data_msgs_rx++;
288		sess->stats.data_bytes_rx += copy_len;
289		sess->stats.last_rx = ktime_get();
290	
291		if (sess->sk)
292			sess->sk->sk_data_ready(sess->sk);
293	
294		return (int)copy_len;
295	}
