387	/* -------------------------------------------------------------------------
388	 * poll
389	 *
390	 * Reports readability when desc state has changed since the last
391	 * recvmsg (i.e. any DATA write has occurred or the buffer is complete).
392	 * Writability is always reported: sendmsg does not block.
393	 * ---------------------------------------------------------------------- */
394	
395	__poll_t psmgr_poll(struct file *file, struct socket *sock,
396			    struct poll_table_struct *wait)
397	{
398		struct sock *sk = sock->sk;
399		struct psmgr_sock *psk = psmgr_sk(sk);
400		struct psmgr_session *sess = psk->session;
401		__poll_t mask = EPOLLOUT | EPOLLWRNORM;
402	
403		sock_poll_wait(file, sock, wait);
404	
405		if (!sess || !sess->validated)
406			return mask;
407	
408		spin_lock_bh(&sess->lock);
409		if (sess->desc->write_count > 0 || sess->desc->token != 0)
410			mask |= EPOLLIN | EPOLLRDNORM;
411		spin_unlock_bh(&sess->lock);
412	
413		return mask;
414	}
