MODULE_LICENSE("GPL");
MODULE_AUTHOR("Embedded Systems Group");
MODULE_DESCRIPTION("AF_PSMGR: session-oriented local IPC with negotiated processing context");

/* -------------------------------------------------------------------------
 * pernet state
 * ---------------------------------------------------------------------- */

unsigned int psmgr_net_id;

static int psmgr_net_init(struct net *net)
{
	struct psmgr_net *pn = psmgr_net(net);
	int i;

	for (i = 0; i < PSMGR_SESSION_HTABLE_SZ; i++)
		INIT_LIST_HEAD(&pn->session_table[i]);
	spin_lock_init(&pn->session_lock);
	atomic64_set(&pn->sessions_created, 0);
	atomic64_set(&pn->sessions_active, 0);
	atomic64_set(&pn->total_exec_calls, 0);
	atomic64_set(&pn->total_seq_errors, 0);
	return 0;
}

static void psmgr_net_exit(struct net *net)
{
	struct psmgr_net *pn = psmgr_net(net);
	struct psmgr_session *sess, *tmp;
	int i;

	/*
	 * At namespace destruction all sockets should already be closed via
	 * normal socket teardown. Walk the table defensively and warn if any
	 * sessions remain, then release their references.
	 */
	spin_lock_bh(&pn->session_lock);
	for (i = 0; i < PSMGR_SESSION_HTABLE_SZ; i++) {
		list_for_each_entry_safe(sess, tmp, &pn->session_table[i], node) {
			pr_warn("psmgr: net exit: session %u still active\n",
					sess->session_id);
			list_del_init(&sess->node);
			psmgr_session_put(sess);
		}
	}
	spin_unlock_bh(&pn->session_lock);
}

static struct pernet_operations psmgr_net_ops = {
	.init = psmgr_net_init,
	.exit = psmgr_net_exit,
	.id   = &psmgr_net_id,
	.size = sizeof(struct psmgr_net),
};

